import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"黑虚闪","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/4.术法/魔法/通用魔法/7.无派系或通用/黑虚闪.md","filePath":"4.资源分区/4.术法/魔法/通用魔法/7.无派系或通用/黑虚闪.md"}'),d={name:"4.资源分区/4.术法/魔法/通用魔法/7.无派系或通用/黑虚闪.md"};function o(p,e,l,_,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"黑虚闪",tabindex:"-1"},[n("黑虚闪 "),r("a",{class:"header-anchor",href:"#黑虚闪","aria-label":'Permalink to "黑虚闪"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),s('<h1 id="黑虚闪-1" tabindex="-1">黑虚闪 <a class="header-anchor" href="#黑虚闪-1" aria-label="Permalink to &quot;黑虚闪&quot;">​</a></h1><p>黑虚闪（差升法术）<br> 为“十刃解放后所使用的强大虚闪”，颜色黑，同王虚的闪光一样是被禁止在天穹之下使用的招式。漫画中只有乌尔奇奥拉使用了这一技能，归刃后的乌尔奇奥拉仅靠一击就粉碎了一护虚化状态下的假面，威力仅次于王虚的闪光。<br> 这是一个基于虚闪的研发技能 只要拥有虚闪这种施法方式就可修习这能力，若使用者不为虚，则需要额外消耗1xp获得新的施法方式【虚闪】使用者使用以【风度+学识+学识：灵压凝聚+专注：灵压爆发】进行施法检定，造成立场伤害，射程为15M。<br> 该法术为差升法术，若无特殊说明，则高等级效果替换低级，下不赘述。</p><p>D+500<br> 类型：增强技<br> 等级：D<br> 派系：无<br> 消耗：2<br> 成分：语言<br> 动作：自由<br> 射程：无<br> 效果：自身<br> 持续：一个场景<br> 在当前场景消耗两点能量强化使用者的虚闪，使其攻击从一般的虚闪升级为【黑虚闪】，在施法时可以造成更加致命的攻击，你在使用虚闪进行施法时额外获得来源于增强加值的1L法术强度，使黑虚闪造成的1点严重伤害转化为韧性伤害，并且你的黑虚闪获得【高速1】和【破魔1】</p><p>C+1000<br> 类型：增强技<br> 等级：C<br> 派系：无<br> 消耗：6<br> 成分：语言<br> 动作：自由<br> 射程：无<br> 效果：自身<br> 持续：一个场景<br> 现在你使用【黑虚闪】所消耗的能量提升为6，现在你使用黑虚闪进行施法时获得的来源于增强加值的法术强度提升为2L并额外获得1dp增强加值，造成的严重伤害转为韧性伤害的值由1点提升至2点。<br> 现在你不再获得D级所获得的破防，而是在高速/破魔中选择一个，获得5点对应破防，若该破防属性结算后仍有剩余则转化为攻击上的增强加值，至多转化5点。 该属性选定后不可更改。</p><p>B+2000<br> 类型：增强技<br> 等级：B<br> 派系：无<br> 消耗：10<br> 成分：语言<br> 动作：自由<br> 射程：无<br> 效果：自身<br> 持续：一个场景<br> 现在你使用【黑虚闪】所消耗的能量提升为10，现在你使用黑虚闪进行施法时获得的来源于增强加值的法术强度提升为2L并额外获得1dp增强加值，造成的严重伤害转为韧性伤害的值由2点提升至3点。<br> 你保留在C级黑虚闪所选择的破防，并且你的黑虚闪获得【超级贯穿】特性。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=a(d,[["render",o]]);export{f as __pageData,m as default};
